import React from 'react';
import clsx from 'clsx';
import { HighlightConsumer } from '../shared';
import { useTreeContext } from './hooks/TreeContext';
import { useTreeNodeContext } from './hooks/TreeNodeContext';
import { isNonNullable } from '../util';
import { TextOverflow } from '../shared/components/text-overflow';

export const TreeNodeLabel = React.forwardRef<HTMLDivElement, React.ComponentPropsWithoutRef<'div'>>(
  ({ className, children, ...restProps }, ref) => {
    const { rootCssScope, labelRenderer } = useTreeContext();
    const { doublyTreeNode: node } = useTreeNodeContext();
    const { disabled, label, value, title } = node.__node__;

    const markRenderer = React.useCallback(
      (text: string) => <span className={clsx(!disabled && rootCssScope('__node-highlight'))}>{text}</span>,
      [disabled, rootCssScope],
    );

    const labelNode: React.ReactNode = (() => {
      if (isNonNullable(children)) {
        return children;
      }
      if (isNonNullable(label)) {
        return label;
      }
      if (isNonNullable(title)) {
        return title;
      }
      if (labelRenderer) {
        return labelRenderer(node);
      }
      return value;
    })();

    const $labelNode = <HighlightConsumer markRenderer={markRenderer}>{labelNode}</HighlightConsumer>;

    return (
      <TextOverflow
        ref={ref}
        as="div"
        className={clsx(rootCssScope('__node__label'), className)}
        lineClamp={1}
        {...restProps}
      >
        {$labelNode}
      </TextOverflow>
    );
  },
);
